import React, { useState } from "react";
import "./MedicinePage.css";

const medicinesData = [
  { name: "Paracetamol", location: "Visakhapatnam", type: "Tablet" },
  { name: "Amoxicillin", location: "Vijayawada", type: "Capsule" },
  { name: "Cetrizine", location: "Hyderabad", type: "Tablet" },
  { name: "Dolo 650", location: "Guntur", type: "Tablet" },
  { name: "Azithromycin", location: "Vishakhapatnam", type: "Syrup" },
  { name: "Metformin", location: "Vijayawada", type: "Tablet" },
  { name: "Cough Syrup", location: "Rajahmundry", type: "Liquid" },
];

const MedicinePage = () => {
  const [searchQuery, setSearchQuery] = useState("");
  const [filteredMedicines, setFilteredMedicines] = useState([]);

  const handleSearch = (e) => {
    const query = e.target.value.toLowerCase();
    setSearchQuery(query);

    if (query.trim() === "") {
      setFilteredMedicines([]);
      return;
    }

    const filtered = medicinesData.filter(
      (item) =>
        item.name.toLowerCase().includes(query) ||
        item.location.toLowerCase().includes(query) ||
        item.type.toLowerCase().includes(query)
    );

    setFilteredMedicines(filtered);
  };

  const handleSelect = (medicine) => {
    setSearchQuery(medicine.name);
    setFilteredMedicines([]);
  };

  return (
    <div className="medicine-page">
      <h2 className="medicine-title">Available Medicines</h2>

      <div className="search-container">
        <input
          type="text"
          value={searchQuery}
          onChange={handleSearch}
          placeholder="Search by name, type or location..."
          className="search-input"
        />
        <button className="search-button">Search</button>

        {filteredMedicines.length > 0 && (
          <ul className="suggestions-list">
            {filteredMedicines.map((medicine, index) => (
              <li
                key={index}
                className="suggestion-item"
                onClick={() => handleSelect(medicine)}
              >
                <div className="medicine-name">{medicine.name}</div>
                <div className="medicine-location">
                  ({medicine.location} • {medicine.type})
                </div>
              </li>
            ))}
          </ul>
        )}
      </div>

      <div className="medicine-cards">
        {filteredMedicines.length === 0 && searchQuery !== "" ? (
          <p className="no-results">No medicines found.</p>
        ) : (
          <p className="default-text">
            Start typing to search for available medicines...
          </p>
        )}
      </div>
    </div>
  );
};

export default MedicinePage;
